import{_ as o,o as i,c as a,a6 as r}from"./chunks/framework.DtxWasON.js";const g=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"mainchain/migrations/index.md","filePath":"mainchain/migrations/index.md"}'),t={name:"mainchain/migrations/index.md"};function n(c,e,d,s,l,p){return i(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Note</p><p>This documentation section is for existing nodes migrating to <code>cosmovisor</code>. For new node installations please see the <a href="./../software/cosmovisor/install_und_with_cosmovisor.html">Install und with Cosmovisor</a> documentation.</p></div><p>Unlike previous upgrades, future upgrades of the FUND Mainchain should not require the full halt/export state/migrate genesis process. As of Cosmos SDK v0.45.x, network upgrades and state changes can occur in-place. This makes upgrading much simpler for node operators, as it means that they can set up an upgrade well in advance.</p><p>Future upgrades will occur via the <code>x/upgrade</code> module, which will require a Governance proposal to pass. Once passed, the <code>und</code> software will automatically halt at the proposed height and wait for the upgraded binary containing the required upgrade information.</p><p>Whilst it is possible to undertake the upgrade process manually, it can be time consuming. The recommended process for managing the <code>und</code> binary and upgrades is to implement <code>cosmovisor</code>.</p><p>The initial process of migrating to using <code>cosmovisr</code> for handling <code>und</code> takes a little additional configuration, but once in place, upgrades are much easier for operators to implement.</p><p>The following guides are available, covering migrating to <code>cosmovisr</code>, and configuring the current upgrades:</p><ol><li><a href="./cosmovisor.html">Using Cosmovisor with und: Quick Start</a> - how to set up <code>cosmovisor</code> to run <code>und</code> and handle upgrades</li><li><a href="./1-init_ibc_upgrade.html">1-init_ibc Upgrade</a> - configuring <code>cosmovisor</code> for the <code>1-init_ibc</code> upgrade</li><li><a href="./2-grog_upgrade.html">2-grog Upgrade</a> - configuring <code>cosmovisor</code> for the <code>2-grog</code> upgrade</li><li><a href="./3-keyleth_upgrade.html">3-keyleth Upgrade</a> - configuring <code>cosmovisor</code> for the <code>3-keyleth</code> upgrade</li><li><a href="./4-percival_upgrade.html">4-percival Upgrade</a> - configuring <code>cosmovisor</code> for the <code>4-percival</code> upgrade</li><li><a href="./5-pike_upgrade.html">5-pike Upgrade</a> - configuring <code>cosmovisor</code> for the <code>5-pike</code> upgrade</li><li><a href="./6-scanlan_upgrade.html">6-scanlan Upgrade</a> - configuring <code>cosmovisor</code> for the <code>6-scanlan</code> upgrade</li></ol>',8)])])}const h=o(t,[["render",n]]);export{g as __pageData,h as default};
